import { NextResponse } from 'next/server';
import { db } from '@/db';
import { users } from '@/db/schema';
import { eq } from 'drizzle-orm';

export async function GET(req: Request, { params }: { params: { id: string } }) {
  const user = await db.select().from(users).where(eq(users.id, parseInt(params.id)));
  return NextResponse.json(user[0]);
}

export async function PUT(req: Request, { params }: { params: { id: string } }) {
  const body = await req.json();
  const updated = await db.update(users).set(body).where(eq(users.id, parseInt(params.id))).returning();
  return NextResponse.json(updated[0]);
}

export async function DELETE(req: Request, { params }: { params: { id: string } }) {
  await db.delete(users).where(eq(users.id, parseInt(params.id)));
  return NextResponse.json({ deleted: true });
}

